local G = DYCLegendary local GetEntHitHeight = G.GetEntHitHeight local function GetMidPoint(p1, p2, h, a) h = h or 0x1 a = math.rad(a or 0x5a) local d = p1:Dist(p2) local a12 = math.atan2(p2.z - p1.z, p2.x - p1.x) local ov = d / 0x2 * h * math.sin(a) local oh = d / 0x2 * h * math.cos(a) local ox, oy, oz = oh * math.cos(a12 + math.pi / 0x2), ov, oh * math.sin(a12 + math.pi / 0x2) return Vector3((p1.x + p2.x) / 0x2 + ox,(p1.y + p2.y) / 0x2 + oy,(p1.z + p2.z) / 0x2 + oz) end local function GetBezier3Pos(p0, p1, p2, p3, t) local k = 0x1 - t return p0 * k * k * k + p1 * 0x3 * t * k * k + p2 * 0x3 * t * t * k + p3 * t * t * t end local function GetBezierPos(p0, p1, p2, t) return p0 * (0x1 - t) * (0x1 - t) + p1 * 0x2 * t * (0x1 - t) + p2 * t * t end local function Hit(self, target, ...) self.dycLastOwner = self.owner if self.dycBezierType then local attacker = self.owner local weapon = self.inst self:Stop() self.inst.Physics:Stop() if not attacker.components.combat and attacker.components.weapon and attacker.components.inventoryitem then weapon = attacker attacker = weapon.components.inventoryitem.owner end if attacker and attacker.components.combat and target and target.IsValid then attacker.dycHitWithNonPrimaryProjectile = self.inst.dycIsNonPrimaryProjectile attacker.components.combat:DoAttack(target, weapon, self.inst) attacker.dycHitWithNonPrimaryProjectile = nil end if self.onhit then self.onhit(self.inst, attacker, target, weapon) end else local attacker = self.owner local weapon = self.inst if not attacker.components.combat and attacker.components.weapon and attacker.components.inventoryitem then weapon = attacker attacker = weapon.components.inventoryitem.owner end if attacker then attacker.dycHitWithNonPrimaryProjectile = self.inst.dycIsNonPrimaryProjectile end local retVal = self.dycOldHit(self, target, ...) if attacker then attacker.dycHitWithNonPrimaryProjectile = nil end self.dycLastOwner = nil return retVal end end local function Throw(self, owner, target, attacker, ...) if self.dycBezierType then local inst = self.inst local hasTarget = target and target.IsValid ~= nil self.owner = owner self.target = hasTarget and target self.hitPointHeight = hasTarget and GetEntHitHeight(target) or 0x0 self.start = Vector3(owner.Transform:GetWorldPosition()) self.dest = hasTarget and Vector3(target.Transform:GetWorldPosition()) + Vector3(0x0, self.hitPointHeight, 0x0) or target if not hasTarget then self.homing = false end local offset = self.launchoffset if attacker and offset then local pos = inst:GetPosition() local facing_angle = attacker.Transform:GetRotation() * DEGREES local offset_vec = Vector3(offset.x * math.cos(facing_angle), offset.y, - offset.x * math.sin(facing_angle)) pos = pos + offset_vec inst.Transform:SetPosition(pos:Get()) elseif hasTarget and offset then local pos = inst:GetPosition() local facing_angle = target.Transform:GetRotation() * DEGREES local offset_vec = Vector3(offset.x * math.cos(facing_angle), offset.y, - offset.x * math.sin(facing_angle)) pos = pos + offset_vec inst.Transform:SetPosition(pos:Get()) end inst:StartUpdatingComponent(self) inst:PushEvent( "onthrown" , {thrower = owner, target = hasTarget and target or nil}) if hasTarget then target:PushEvent( "hostileprojectile" , {thrower = owner, attacker = attacker, target = target}) end if self.onthrown then self.onthrown(self.inst, owner, hasTarget and target or nil) end if self.cancatch and hasTarget and target.components.catcher then target.components.catcher:StartWatching(self.inst) end local inst = self.inst inst.Physics:SetVel(0x0, 0x0, 0x0) self.dycStart = Vector3(inst.Transform:GetWorldPosition()) self.dycDistCovered = 0x0 else return self.dycOldThrow(self, owner, target, attacker, ...) end end local function OnUpdate(self, dt, ...) if self.dycBezierType then local target = self.target if self.homing and (not target or not target:IsValid() or target:IsInLimbo()) then self:Miss(target) return end local inst = self.inst if self.homing and target and target:IsValid() and not target:IsInLimbo() then self.dest = Vector3(target.Transform:GetWorldPosition()) + Vector3(0x0, self.hitPointHeight, 0x0) end local dest = self.dest local start = self.dycStart local pos = Vector3(inst.Transform:GetWorldPosition()) local distCovered = self.dycDistCovered local distVirtual = self.dycBezierCalcDist distVirtual = distVirtual and distVirtual > 0x0 and distVirtual or math.sqrt(math.pow(start.x - dest.x, 0x2) + math.pow(start.z - dest.z, 0x2)) + (self.dycBezierExtraDist or 0x0) local t = distCovered / distVirtual local moveDist = self.speed * TheSim:GetTickTime() * TheSim:GetTimeScale() t = math.min(0x1, t + moveDist / distVirtual) self.dycDistCovered = self.dycDistCovered + moveDist local newPos = nil if self.dycBezierType == 0x3 and self.dycBezierP1 and self.dycBezierP2 then newPos = GetBezier3Pos(start, self.dycBezierP1, self.dycBezierP2, dest, t) else local midPoint = nil if self.homing then midPoint = GetMidPoint(start, dest, self.dycBezierH, self.dycBezierAngle) else if not self.dycMidPoint then self.dycMidPoint = GetMidPoint(start, dest, self.dycBezierH, self.dycBezierAngle) end midPoint = self.dycMidPoint end newPos = GetBezierPos(start, midPoint, dest, t) end inst.Transform:SetPosition(newPos:Get()) local distLeft2D = math.sqrt(math.pow(newPos.x - dest.x, 0x2) + math.pow(newPos.z - dest.z, 0x2)) if distLeft2D <= self.hitdist then self:Hit(target) return end local distCovered = newPos:Dist(start) if self.range and distCovered > self.range then self:Miss(target) return end else return self.dycOldOnUpdate(self, dt, ...) end end local function SetBezier(self, h, angle) self.dycBezierType = 0x2 self.dycBezierH = h or 0x1 self.dycBezierAngle = angle or 0x5a end local function SetBezier3(self, p1, p2) self.dycBezierType = 0x3 self.dycBezierP1 = p1 self.dycBezierP2 = p2 end local function SetBezierCalcDist(self, d) self.dycBezierCalcDist = d end local function DYCProjectile(projectile) projectile.dycOldOnUpdate = projectile.OnUpdate projectile.OnUpdate = OnUpdate projectile.dycOldThrow = projectile.Throw projectile.Throw = Throw projectile.dycOldHit = projectile.Hit projectile.Hit = Hit projectile.SetBezier = SetBezier projectile.SetBezier3 = SetBezier3 projectile.SetBezierCalcDist = SetBezierCalcDist end return DYCProjectile 